#include <bits/stdc++.h>
using namespace std;
int main(){
    int L,s=0,n=0,i,j;
    cin>>L;
    if(L==1){
		cout<<"0";
		return 0;
	}
    while (s<=L){
        for (i=2;i<L;i++){
            j=2;
            while (j<=sqrt(i)){
               if (i%j==0) break;
                j++;
            }
            if (j>sqrt(i)){
                s=s+i;    
                if (s>L){
                break;
            }
                else{
                    n=n+1;
                    cout<<i<<endl; 
                }  
                }     
        }
    }
    cout<<n;
}
